#include "temp_control_mixed_u_ros_cpp_pkg/user_headers/tcp_opInterface_src.hpp"

// Do not edit this file as it will be overwritten if HAMR codegen is rerun

tcp_opInterface::tcp_opInterface() : tcp_opInterface_base()
{
    // Invoke initialize entry point
    initialize();

    PRINT_INFO("tcp_opInterface infrastructure set up");
}

int main(int argc, char **argv)
{
    rclcpp::init(argc, argv);
    auto executor = rclcpp::executors::MultiThreadedExecutor();
    auto node = std::make_shared<tcp_opInterface>();
    executor.add_node(node);
    executor.spin();
    rclcpp::shutdown();
    return 0;
}
